var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"의외로군.","JPN":"想定の範囲外。","ENG":"This is rather unexpected.","TWN":"真意外啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"당연히 <color=#ffd34c>그 사람</color>이 제일 먼저 찾아올 거라고 생각했는데.","JPN":"当然<color=#ffd34c>あの人</color>が真っ先に訪ねてくるだろうと思っていたのだが。","ENG":"I thought naturally <color=#ffd34c>you know who</color> would be the first to visit me.","TWN":"我還以為<color=#ffd34c>那個人</color>會最先來的呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......실망시켜서 유감이군.","JPN":"……残念だったな。","ENG":"Sorry to disappoint.","TWN":"……可惜讓妳失望了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 신입 애송이와 널 만나게 하는 건 아무래도 위험부담이 커서 말이지.","JPN":"でも、新人を貴様に会わせるのはどうしても危険要素が大きいからな。","ENG":"But it’s too risky to let the rookie come see you just yet.","TWN":"畢竟讓妳和新來的小鬼頭見面的風險太大了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"굳이 일부러 문제를 만들 필요는 없으니까.","JPN":"わざわざ災いの元を作る必要もないだろう。","ENG":"No need to make things more difficult than necessary.","TWN":"沒必要刻意製造問題。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......그런가?","JPN":"……そうだろうか？","ENG":"Is that so?","TWN":"……是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"쓸데없는 걱정이라고 생각하지만...... 뭐, 알겠다.","JPN":"余計な心配だと判断するが……まあ、わかった。","ENG":"I would say you worry over nothing... but very well.","TWN":"雖然是妳無謂的擔心……算了，我知道了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 지내는 건 어때? 불편한 점은 없나?","JPN":"それより調子はどうだ？　不便なところはないか？","ENG":"Anyway, how are you getting along here? Everything comfortable enough for you?","TWN":"話說回來，妳過得怎麼樣？有什麼不方便的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그다지.","JPN":"とくには。","ENG":"More or less.","TWN":"沒什麼特別的地方。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"구속구가 좀 거추장스럽긴 하지만, 큰 문제는 없다.","JPN":"拘束装置が少し邪魔だが、大した問題ではない。","ENG":"The restraints are rather inconvenient, but it’s bearable enough.","TWN":"雖然拘留所挺煩人的，但是問題不大。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다행이군. 그래도 조심하라고.","JPN":"それはよかった。でも、気をつけろよ。","ENG":"Good. Still, be careful.","TWN":"那就好。但妳還是要小心點。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"괜히 힘으로 풀려고 했다간 내장되어 있는 폭탄이 터질 거다.","JPN":"下手に力で解こうとしたら、内蔵爆弾が爆発するだろうから。","ENG":"If you try to force them loose, you’ll set off the internal explosives.","TWN":"如果妳想要用蠻力逃脫的話，內藏的炸彈就會引爆。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"피차 지저분한 꼴은 보고 싶지 않겠지?","JPN":"お互い、汚らわしい姿は見たくないだろう？","ENG":"Neither of us would want to deal with that mess, right?","TWN":"我們彼此都不想看到這種可怕的情況吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......알겠다. 기억해 두지.","JPN":"……わかった。記録する。","ENG":"...Understood. I’ll keep that in mind.","TWN":"……我知道。我會記住的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래서 용건은 뭐지?","JPN":"さて、用件は何？","ENG":"So what is the purpose of your visit?","TWN":"不過妳是來做什麼的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"설마 내 처우개선을 위해 여기까지 온 건 아닐 텐데.","JPN":"まさか私の処遇改善のために\\nここまで来たわけではないだろうし……","ENG":"I hardly think you came to check in on my welfare during captivity.","TWN":"總不會是為了來改善我的待遇吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 내가 묻고 싶은 질문이로군.","JPN":"それはこっちが聞きたいことだ。","ENG":"I was about to ask you the same question.","TWN":"這才是我想問的問題呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"항복이라니, 그런 헛소리를 정말 믿을 거라고 생각한 건 아니겠지?","JPN":"降参なんて、そんなたわ言を本気で信じると思ってないだろうな？","ENG":"You don’t really expect us to believe you've surrendered in earnest, do you?","TWN":"妳不會以為我真的會相信投降這種鬼話吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이런 상황을 만든 진짜 목적에 대해 듣고 싶은데.","JPN":"こんな状況を作った本当の目的について聞きたい。","ENG":"I’d like to hear the real reason why you would shape the situation like this.","TWN":"我想知道妳為什麼要這麼做。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"거래를 하고 싶다.","JPN":"取引がしたい。","ENG":"I want to strike a deal with you.","TWN":"我想做個交易。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"거래?","JPN":"取引？","ENG":"A deal?","TWN":"交易？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래. 지금 너희들에게 가장 절실한 건 역시 정보겠지?","JPN":"そうです。今、あなたたちが一番欲しいのは情報ですね？","ENG":"That’s right. What you need the most right now is information, correct?","TWN":"對。現在對你們最實際的東西，果然是情報對吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"나는 시스템 테라사이드의 의사조정권자로서, 너희가 궁금해 할 거의 모든 것들에 대한 정보를 가지고 있다.","JPN":"私はテラサイドシステムの意思調整者として、\\nあなたたちが欲しがっているほとんどの情報を知っている。","ENG":"As the Arbiter of the System Terraside, I have information on nearly everything you would be curious about.","TWN":"我是特拉賽德系統的裁決者，你們想要的情報我都有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"본부의 위치, 병력의 편제, 로스트 쉽의 재생 메커니즘......","JPN":"本部の位置、兵力の編制、\\nロストシップの再生メカニズム……","ENG":"The location of the headquarters, troop organization, the mechanism behind the regeneration of the Lost Ship...","TWN":"總部的位置、兵力的編制、失落艦船的再生原理……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"뭐든 원한다면 전적으로 협조하지.","JPN":"望むなら、何でも全面的に協力する。","ENG":"I’d be willing to provide any information you desire.","TWN":"你們想要做什麼，我會全面協助你們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"대신......","JPN":"その代わり……","ENG":"In exchange...","TWN":"但是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대신?","JPN":"その代わり？","ENG":"In exchange for what?","TWN":"但是？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그녀와 이야기하고 싶다. 단 둘이.","JPN":"彼女と話したい。二人きりで。","ENG":"I'd like to speak with her. In private.","TWN":"我要和那個女人說話，就我們兩個。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......하하.","JPN":"……ハハハ。","ENG":"Haha...","TWN":"……哈哈。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제법 괜찮은 제안이군.","JPN":"なかなかいい提案だな。","ENG":"That’s a tempting offer.","TWN":"真是不錯的提議。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 거절한다.","JPN":"だが、断る。","ENG":"But I must decline.","TWN":"但是我拒絕。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......어째서?","JPN":"……なぜ？","ENG":"Why?","TWN":"……為什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"유감스럽게도 난 네가 말한 것들은 전혀 궁금하지 않거든.","JPN":"残念ながら、私は貴様が言ったことに全然興味ないんだ。","ENG":"Unfortunately for you, I’m not curious about any of the things you just mentioned.","TWN":"真可惜，我對妳說的事情完全不感興趣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다는 네가 이런 위험을 무릅쓰면서까지 굳이 신입 애송이를 만나려는 의도가 더 의심스러운걸?","JPN":"それよりも、こんな危険を冒してまで新人に会いたがってる理由が気になる。","ENG":"If anything, I find it suspicious that you’d be willing to risk so much just so that you can secure a private audience with the rookie.","TWN":"比起這些，最可疑的是妳不惜冒著這麼大的危險，就只為了見那個小鬼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네놈들도, 그리고 나유빈도......","JPN":"貴様も、そしてイチノセも……","ENG":"It’s not just you lot, but Na Yubin as well...","TWN":"你們也好，羅瑜斌也好……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석을 두고 각자 이런저런 꿍꿍이들이 있는 것 같던데.","JPN":"あいつに対してそれぞれの思惑があるようだった。","ENG":"You all seem to be plotting something involving the rookie.","TWN":"全都詭計多端。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그걸 뻔히 알면서도 신입을 네 앞에 대령할 정도로 나는 바보가 아니야.","JPN":"それを知りながら、新人をここに来させるほど私はバカではない。","ENG":"I’m not so stupid that I’d serve her to you on a silver platter when I know something's going on.","TWN":"知道妳心懷鬼胎，還把新人帶來見妳，我可沒有這麼笨。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......후회할 텐데?","JPN":"後悔すると思うが。","ENG":"You’ll regret this...","TWN":"……妳不後悔嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"넌 모르겠지만 시스템 테라사이드는 사실......","JPN":"あなたにはわからないだろうが、テラサイドシステムは実は……","ENG":"There’s something you don’t know. The System Terraside is actually...","TWN":"妳所不知道的特拉賽德系統，其實是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......구 관리국의 현실간섭계 기술들 중 하나인, <color=#ffd34c>불멸체 시스템</color>을 대충 변형한 아류작이겠지.","JPN":"……旧管理局の現実干渉系スキルの一つである、<color=#ffd34c>不滅体システム</color>を大まかに変形させた派生形だろうな。","ENG":"A knockoff version of the <color=#ffd34c>Immortal System</color>, one of the reality interference technologies of the Old Administration.","TWN":"舊管理局的現世干涉技術之一，大概是由<color=#ffd34c>不滅者系統</color>變形後的模仿作。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"엘릭서인가 뭔가 하는 걸 뿌린 이유도 맞춰 볼까?","JPN":"エリクサーとやらを散布した理由も当ててみようか？","ENG":"Let me guess why you’ve been spreading around the Elixir as well.","TWN":"要不要我再猜猜你們為什麼散布聖水？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"불멸체 시스템을 기동하려면 엄청난 양의 초월 변이 인자가 필요하지.","JPN":"不滅体システムを起動するには、膨大な量の超越変異ファクターが必要だ。","ENG":"In order to operate the Immortal System, you will need tremendous amounts of Transcendental Mutation Factor.","TWN":"因為要啟動不滅者系統，需要大量的超越變異因子吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아마 네놈들은 그걸 리플레이서 인자라고 부르는 것 같은데.","JPN":"貴様らはそれをリプレイサー・ファクターと呼んでいるようだが。","ENG":"I believe you guys call it the Replacer Factor.","TWN":"不過你們好像把它叫做克隆因子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"변이 인자의 대량생산을 위해 인간을 공장 대용으로 사용한 거겠지.","JPN":"変異ファクターの大量生産のために、\\nきっと人間を工場代わりに使ったのだろう。","ENG":"You must have used human bodies as the factories for mass producing the Mutation Factor.","TWN":"你們為了大量生產變異因子，把人類當作工廠來使用。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 사실 이터니움으로 만든 자가증식형 나노머신이니까.","JPN":"それはまさに、エタニウムで作った\\n自己増殖型ナノマシンだからな。","ENG":"Because it’s basically a self-replicating nanomachine made of Eternium.","TWN":"因為那其實是用永恆之金做的自身增殖型的奈米機器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어때? 내 말이 틀렸나?","JPN":"どうだ？　私の話、間違ってるか？","ENG":"Well? Am I wrong?","TWN":"怎麼樣？我有說錯的地方嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"어떻게 그런 것까지 알고 있는 거지?","JPN":"どうしてそんなことまで知っているのですか？","ENG":"How do you know all that?","TWN":"妳怎麼會連這種事都知道？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"당신 설마......?","JPN":"まさか、あなた……","ENG":"Could you be...","TWN":"難道妳……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하하......","JPN":"ハハハ……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 말이지, 그동안 너희 같은 미친 놈들을 정말 신물 나게 봐 왔어.","JPN":"私はな、今まで貴様らのような気狂い野郎を\\nうんざりするほど見てきたんだよ。","ENG":"I've dealt with crazies like you all my life.","TWN":"我啊，這段時間看你們這些瘋子都看到煩了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이런 짓거릴 벌이는 건 네놈들이 처음도 아니고......","JPN":"こんなことをするのは貴様らが初めてでもないし……","ENG":"You're not the first to try something like this...","TWN":"你們這些傢伙也不是第一次做這種事情了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아마 마지막도 아니겠지.","JPN":"たぶん最後でもないだろう。","ENG":"And you probably won't be the last either.","TWN":"恐怕也不會是最後一次吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사람들을 괴물로 만들고, 세상을 지옥으로 바꿔서 뭘 어쩌고 싶은지는 모르겠지만......","JPN":"人々を怪物にして、世の中を地獄に変えて、\\n何をどうしたいのかわからないが……","ENG":"I don’t know what you hope to achieve by turning people into monsters and this world into a living hell...","TWN":"雖然我不知道你們為什麼要把人變成怪物，把世界變成地獄……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네놈들의 시답잖은 계획이 뭐든, 생각대로 되진 않을 거다.","JPN":"貴様らのくだらない計画が何であれ、\\n思うようにはいかないだろう。","ENG":"But whatever your lame plan is, it won't go the way you want.","TWN":"但你們那令人不爽的計畫都不會成功的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......리플레이서 인자? 시스템 테라사이드? 놀고들 있군.","JPN":"……リプレイサー・ファクター？\\nテラサイドシステム？　ふざけるな。","ENG":"Replacer Factor? System Terraside? Don’t make me laugh.","TWN":"……克隆因子？特拉賽德系統？真是笑話。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정말 그런 꿈같은 기술이 있었으면 구 관리국이 망할 일도 없었을 거라고 생각하지 않나?","JPN":"本当にそんな夢のような技術があったら、旧管理局がつぶれることもなかったと思わないか？","ENG":"If such miracle technologies really existed, do you think the Old Administration would have fallen like that?","TWN":"妳也不想想，要是真有這種夢幻般的技術，舊管理局不就不會毀掉了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이름은 거창하지만 결국은 결함 시스템이다.","JPN":"名前は立派に見えても、結局のところは欠陥システムだ。","ENG":"These systems may sound fancy, but they're fundamentally flawed.","TWN":"名字取得倒是很厲害，其實也就是個有缺陷的系統。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무력화시킬 방법은 얼마든지 있어.","JPN":"無力化させる方法はいくらでもある。","ENG":"There’s always a way to compromise them.","TWN":"要讓這個系統無力化的方法要多少有多少。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이젠 알겠지? 네가 말한 거래는 내게 그다지 큰 매력이 없다는 걸.","JPN":"もうわかっただろう？　お前が言った取引は、\\n私にとって魅力がないということを。","ENG":"Do you understand now? Your offer carries little weight with me.","TWN":"現在妳知道了吧？妳所說的交易對我一點吸引力也沒有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 쓸데없는 기대는 접고, 쉴 수 있을 때 푹 쉬라고.","JPN":"じゃあ、無駄な期待はやめて、休めるうちにゆっくり休んでおけ。","ENG":"So don’t get your hopes up, and get some rest while you still can.","TWN":"那就收起妳那些無聊的期待，趁能休息的時候好好休息吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"신병 인도가 끝나고 나면, 널 기다리는 건 심문과 자백제뿐일 테니까.","JPN":"身柄引き渡しが終わったら、\\nお前を待っているのは審問と自白剤だけだからな。","ENG":"The only things awaiting you are interrogation and truth serum, once we turn you in.","TWN":"等移交妳的任務結束後，等待妳的就只有審問和招供了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"잠깐.","JPN":"待て。","ENG":"Hang on.","TWN":"等等。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......아직 할 말이 남았나?","JPN":"……まだ言いたいことがあるのか?","ENG":"You still got something to say?","TWN":"……妳還有什麼要說的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그럼 당신은 어떻지?","JPN":"じゃあ、あなたはどうだ？","ENG":"What about you?","TWN":"那妳呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......무슨 뜻이지?","JPN":"……どういう意味だ？","ENG":"What do you mean?","TWN":"……什麼意思？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"당신 말대로 나나, 그 남자가 그녀에 대한 다른 속셈을 가지고 있을지도 모르지.","JPN":"あなたの言う通り、私やあの男は\\n彼女に対して何か企んでいるかもしれない。","ENG":"Like you said, I or the other man may be plotting something involving the girl.","TWN":"就像妳說得一樣，我和那個男人對她都別有居心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"하지만 어쨌든 간에 지금 그녀를 손에 쥐고 있는 것은 바로 당신 아닌가?","JPN":"だが、いずれにせよ\\n今彼女を手にしているのはあなただ。","ENG":"But you're the one who has custody of her right now, aren’t you?","TWN":"但是不管怎麼樣，現在她不是落入了妳的手裡嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그녀에 대한 당신의 계획은 뭐지?","JPN":"あなたは彼女をどうするつもりだ？","ENG":"So what’s your plan for her?","TWN":"為了她，妳的計畫是什麼呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"당신은 대체 뭣 때문에 그녀를 둘러싼 모든 진실로부터 차단하고 있는 거지?","JPN":"あなたはいったい何のために、彼女を取り巻く全ての真実から遮断している？","ENG":"Why are you shielding her from the truth about her?","TWN":"妳到底是為什麼要對她隱瞞所有的真相呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그러게 말입니다. 대체 이유가 뭘까요?","JPN":"ハハ、確かにそうですよね。いったい何のためでしょうね。","ENG":"Haha, I know, right? Why indeed?","TWN":"哈哈，是啊，到底是為什麼呢？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님.","JPN":"師匠。","ENG":"Master?","TWN":"師父。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......주시윤.","JPN":"……アキヤマ。","ENG":"Shiyoon...","TWN":"……周時雲。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설마...... 엿듣고 있었나?","JPN":"まさか……盗み聞きしていたのか？","ENG":"Were you... eavesdropping?","TWN":"你該不會……剛才就在偷聽吧？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"평소에 심문 따위는 관심도 없으시던 분이 남들 눈을 피해 살금살금 포로를 만나러 가시는데......","JPN":"普段尋問など興味ない人が、人目を避けてこっそり捕虜に会いにくるというのに……","ENG":"When someone who normally couldn’t care less about interrogation sneaks off to see the prisoner...","TWN":"平時對審問毫無興趣的人，今天卻趁人不注意，偷偷來見俘虜……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 궁금증이 동하지 않을 수가 없죠.","JPN":"興味ないわけありませんよ。","ENG":"I am bound to get curious.","TWN":"我沒有辦法不去好奇啊。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 호기심은 명줄 단축의 지름길이라고 가르쳤을 텐데.","JPN":"余計な好奇心は寿命を縮めるだけだと教えたはずだが。","ENG":"Didn’t I teach you, curiosity killed the cat?","TWN":"好奇心會害死貓，我應該有教過你的。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"벌써 잊어버린 거냐?","JPN":"もう忘れたのか？","ENG":"Or have you already forgotten?","TWN":"你已經忘了嗎？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이를테면......","JPN":"たとえば……","ENG":"Cats? You mean...","TWN":"比如說……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......제 부모님들처럼 말인가요?","JPN":"僕のご両親のように、ですか？","ENG":"...like my parents?","TWN":"像我父母一樣的意思？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너.......","JPN":"お前……","ENG":"You...","TWN":"你……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 아시다시피 제가 그리 모범적인 제자는 아니라서요.","JPN":"ご存知のように、僕はそこまで\\n優等生な弟子ではありませんからね。","ENG":"As you know, I’m not exactly a model apprentice anyway.","TWN":"但是，就像妳知道的那樣，我不是什麼模範好弟子。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 스승님도 자기 말을 지키지 않는 건 마찬가지죠.","JPN":"そして師匠も自分の\\n言ったことを守らないのは同じです。","ENG":"And even if I remember what you told me, I can be a bit of a rebel.","TWN":"而且師父也沒有遵守自己說的話啊。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다시 돌아오신 후부터, 아니 정확히는......","JPN":"戻ってこられてから、いや正確には……","ENG":"Especially since you returned... or to be precise...","TWN":"自從妳再次回來之後，或者更準確地說……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양을 만난 후로 말입니다.","JPN":"ミナさんに会ってからです。","ENG":"Since I met Mina.","TWN":"自從妳見到米娜小姐之後。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말씀해 보세요, 스승님.","JPN":"教えてください、師匠。","ENG":"Tell me, Master.","TWN":"請告訴我，師父。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 힘</color>을 사용한 자는 <color=#ffd34c>처분</color>하는 게 원칙 아니었나요?","JPN":"<color=#ffd34c>あの力</color>を使った者は<color=#ffd34c>処分</color>するのが原則だったでしょう。","ENG":"Hasn’t it been your policy to <color=#ffd34c>dispose</color> of anyone who’s used <color=#ffd34c>that power</color>?","TWN":"<color=#ffd34c>解決</color>使用<color=#ffd34c>那個力量</color>的人，是師父的原則吧？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 그 알 수 없는 검을 뽑았을 때......","JPN":"ミナさんがその得体の知れない剣を抜いた時。","ENG":"When Mina drew that mysterious sword...","TWN":"米娜小姐拔出那把無名之劍的時候……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 이면세계에서 나유빈이라는 자와 대면했을 때......","JPN":"そして、裏世界でイチノセ・カオルという者と対面した時。","ENG":"...and when she faced off with that Na Yubin guy in the Counterside...","TWN":"還有在異界和羅瑜斌對決的時候……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조금씩이긴 하지만, 미나 양은 분명 <color=#ffd34c>그 힘</color>을 사용하고 있었습니다.","JPN":"少しではありますが、ミナさんは間違いなく<color=#ffd34c>あの力</color>を使っていました。","ENG":"...Mina definitely used <color=#ffd34c>the power</color> albeit only a little each time.","TWN":"雖然只用了一點點，但米娜小姐明顯使用了 <color=#ffd34c>那個力量</color>。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마 몰랐다고 하실 생각은 아니시겠죠?","JPN":"まさかシラを切るつもりではないでしょうね。","ENG":"You’re not going to tell me you didn’t know that, are you?","TWN":"妳不會說妳不知道吧？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 스승님은 미나 양에게 아무런 조치도 취하지 않았죠.","JPN":"しかし、師匠はミナさんに\\n何の措置も取りませんでした。","ENG":"But you haven’t done anything to Mina about it.","TWN":"但是師父對米娜小姐沒有任何處置。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 본인에게 경고를 하는 것도 아니고......","JPN":"だからといって、\\n本人に警告をするわけでもないし……","ENG":"You didn't even warn her about...","TWN":"也沒有警告她……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비숍 재생체의 말처럼 모든 진실로부터 미나 양을 격리하고 계실 뿐이죠.","JPN":"ビショップ再生体が言うように、\\nすべての真実からミナさんを切り離しているだけです。","ENG":"You only shielded her from the truth, just as the Regenerated Bishop said.","TWN":"就像大主教再生體說的，妳只是對米娜小姐隱瞞了真相。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"마치 소중히 기르던 화초가 바깥 바람에 시들기라도 할 것처럼요.","JPN":"まるで大事に育ててきた花が、\\n外の風で散ってしまわないか案ずるように。","ENG":"It’s as if you're worried a fern you tended to so delicately would wither from exposure to sunlight.","TWN":"就像擔心自己悉心呵護的花朵被外面的風吹謝了一樣。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어째서 미나 양은 예외인 거죠?","JPN":"どうしてミナさんは例外なんですか？","ENG":"So, what makes Mina the exception?","TWN":"為什麼米娜小姐會是個例外呢？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 부모님과 미나 양은...... 대체 뭐가 다른 거죠?","JPN":"僕の両親とミナさんは、いったい何が違うんですか？","ENG":"What makes her so different... from my parents?","TWN":"我的父母和米娜小姐……到底有什麼不同呢？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대답해 보세요, 스승님.","JPN":"答えてください、師匠。","ENG":"Tell me, Master.","TWN":"回答我啊，師父。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"왜 미나 양만이 그렇게 특별한 건가요?","JPN":"なぜミナさんだけがそんなに特別なんですか？","ENG":"What makes her so special?","TWN":"為什麼就只對米娜小姐有特殊待遇？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......거절한다.","JPN":"……断る。","ENG":"I will not answer that.","TWN":"……我拒絕回答。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님.","JPN":"師匠。","ENG":"Master?","TWN":"師父。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"널 제자로 거둔 날 말했었지?","JPN":"お前を弟子にした日に言っただろ？","ENG":"Remember what I said when I took you in as my apprentice?","TWN":"我收你為徒的時候說過吧？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"복수를 원하든, 답을 원하든......","JPN":"望むことが復讐であろうが、その答えだろうが……","ENG":"Whether you wanted revenge or an answer...","TWN":"不管你是要復仇，還是要答案……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언제든지 받아 줄 테니 네 힘으로 얻어내라고.","JPN":"いつでも受け止めてやるから、自分の力で掴みとれ、と。","ENG":"...you would have to earn it through your own strength.","TWN":"我無論何時都會接受的，所以用你的力量去奪取吧。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"널 만난 지도 시간이...... 벌써 이렇게 흘렀군.","JPN":"お前と知り合ってからずいぶん……時間が経ったよな。","ENG":"It’s been many years... since I've met you like that.","TWN":"從第一次見到你……已經過去這麼久了。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어때? 이제 자신감이 좀 생겼나?","JPN":"どうだ？　自信はついたか？","ENG":"Well? Are you confident enough now?","TWN":"怎麼？覺得現在有點自信了嗎？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"지금 한 번 해볼 생각이냐?","JPN":"なんなら、今やってみるか？","ENG":"Do you want to test your mettle now?","TWN":"現在想要試試看了？"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 강습대 B1! 목표 함선 내부 진입에 성공했다!</color>","JPN":"<color=#ffd34c>こちらは強襲部隊B1！　目標艦船の内部に侵入成功した！</color>","ENG":"<color=#ffd34c>This is Strike Team B1! We've successfully infiltrated the target ship's cabin!</color>","TWN":"<color=#ffd34c>突襲隊B1報告！成功進入目標艦船內部！</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>적성 대상과 조우! 교전을 개시하겠다. 수색대는 목표물 탐색에 집중할 것!</color>","JPN":"<color=#ffd34c>敵性対象と遭遇！　交戦を開始する。\\n捜索隊は目標物探索に集中するように！</color>","ENG":"<color=#ffd34c>We've made contact with the hostiles! Engaging. Search teams, focus on finding the asset!</color>","TWN":"<color=#ffd34c>發現敵人！開始交戰。搜查隊集中搜尋目標！</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 이것들은?!","JPN":"何だ、こいつらは！？","ENG":"Who are they?","TWN":"怎麼了，這些傢伙？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......아마도 리플레이서 병사들인 것 같군요.","JPN":"どうやらリプレイサー兵士みたいですね。","ENG":"Must be troops from the Replacer.","TWN":"……好像是克隆士兵的樣子呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 설마 함내에까지 쳐들어 올 줄이야......","JPN":"でもまさか、艦内にまで攻め込んでくるとは。","ENG":"Who knew they'd come crashing into the ship?","TWN":"但是，他們竟然會攻進艦船內部……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 단단히 작정한 모양인데요?","JPN":"どうやら相当覚悟を決めたようですね。","ENG":"They must be getting pretty desperate...","TWN":"看來是要決一死戰的樣子呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};